        value: u64,
    }

    struct Capability<[[SLOT phantom_param]]> has [[SLOT cap_abilities]] {}

    struct MasterKey has [[SLOT key_abilities]] {}

    public fun create_resource(value: u64): Resource {
        Resource { value }
    }

    public fun issue_capability<T: store>(_resource: &Resource): Capability<Resource> {
        Capability<Resource> {}
    }

    public fun read_with_capability(cap: &Capability<Resource>): u64 {
        // In real implementation, cap would reference the actual resource
        // For this kata, we demonstrate the type system works correctly
        let _ = cap;
        42 // Simplified - real implementation would need resource access
    }

    public fun consume_with_key(resource: Resource, _key: &MasterKey): u64 {
        let Resource { value } = resource;
        value
    }

    #[test]
    fun test_resource_creation() {
        let res = create_resource(100);
        let Resource { value } = res;
        assert!(value == 100, 0);
    }

    #[test]
    fun test_capability_copy() {
        let res = create_resource(42);
        let cap = issue_capability(&res);
        let cap2 = copy cap; // Must compile - cap has copy ability
        let _ = cap;
        let _ = cap2;
        let Resource { value: _ } = res;
    }

    #[test]
    fun test_master_key_drop() {
        let key = MasterKey {};
        let res = create_resource(99);
        let value = consume_with_key(res, &key);
        assert!(value == 99, 1);
        // key automatically dropped - has drop ability
    }

    #[test]
    fun test_consumption_with_key() {
        let key = MasterKey {};
        let res = create_resource(256);
        let extracted = consume_with_key(res, &key);
        assert!(extracted == 256, 2);
    }
}
